static float DirBands(float px, float py, float dir, int hc, float po)
{
    var wd = dir - MathF.Floor(dir);
    var sec = Math.Min(3, (int)MathF.Floor(wd * 4f));
    var bl = SmoothStep(wd * 4f - sec);
    var h = Math.Max(1, hc);
    var hz = 0.5f + 0.5f * MathF.Sin(px * h + po);
    var dd = 0.5f + 0.5f * MathF.Sin((px + py) * h + po);
    var vt = 0.5f + 0.5f * MathF.Sin(py * h + po);
    var du = 0.5f + 0.5f * MathF.Sin((px - py) * h + po);
    if (sec == 0) return Lerp(hz, dd, bl);
    if (sec == 1) return Lerp(dd, vt, bl);
    if (sec == 2) return Lerp(vt, du, bl);
    return Lerp(du, hz, bl);
}

static float SelW(float t, float c0, float c1, float c2, float c3)
{
    if (t < 0.18f) return Lerp(c0, c1, SmoothStep(0.02f, 0.18f, t));
    if (t < 0.42f) return Lerp(c1, c2, SmoothStep(0.18f, 0.42f, t));
    if (t < 0.72f) return Lerp(c2, c3, SmoothStep(0.42f, 0.72f, t));
    return Lerp(c3, c0, SmoothStep(0.72f, 0.96f, t));
}

var size = context.TileSize;
var seed = GetInt(parameters, "seed", 42);
var waveScale = GetFloat(parameters, "waveScale", 0.5f);
var depthVariation = GetFloat(parameters, "depthVariation", 0.4f);
var choppiness = GetFloat(parameters, "choppiness", 0.3f);
var foamDensity = GetFloat(parameters, "foamDensity", 0.2f);
var currentStrength = GetFloat(parameters, "currentStrength", 0.3f);
var currentDirection = GetFloat(parameters, "currentDirection", 0.5f);

// Water palette (0..1 floats)
var abyssR = 18f / 255f; var abyssG = 44f / 255f; var abyssB = 118f / 255f;
var deepR = 28f / 255f; var deepG = 72f / 255f; var deepB = 152f / 255f;
var midR = 50f / 255f; var midG = 112f / 255f; var midB = 188f / 255f;
var shallowR = 84f / 255f; var shallowG = 156f / 255f; var shallowB = 214f / 255f;
var crestR = 132f / 255f; var crestG = 196f / 255f; var crestB = 236f / 255f;
var sparkleR = 204f / 255f; var sparkleG = 236f / 255f; var sparkleB = 255f / 255f;
var foamR = 238f / 255f; var foamG = 248f / 255f; var foamB = 255f / 255f;

var result = new PixelBuffer(size, size);
result.ParallelForEachPixel((x, y) =>
{
    var phaseX = x / (float)size * 6.2832f;
    var phaseY = y / (float)size * 6.2832f;

    var basin = TileableFractalNoise(x * (0.95f + depthVariation * 0.85f) / (float)size * 6.2832f, y * (0.95f + depthVariation * 0.85f) / (float)size * 6.2832f, Math.Max(2, (int)((float)size * (0.95f + depthVariation * 0.85f) / 6.2832f)), 2, 0.58f, 2f, seed);
    var pocket = TileableFractalNoise(x * (1.7f + depthVariation * 1.25f) / (float)size * 6.2832f, y * (1.7f + depthVariation * 1.25f) / (float)size * 6.2832f, Math.Max(2, (int)((float)size * (1.7f + depthVariation * 1.25f) / 6.2832f)), 2, 0.54f, 2f, seed + 17);
    var currentField = TileableFractalNoise(x * (2.15f + currentStrength * 2.2f) / (float)size * 6.2832f, y * (2.15f + currentStrength * 2.2f) / (float)size * 6.2832f, Math.Max(2, (int)((float)size * (2.15f + currentStrength * 2.2f) / 6.2832f)), 2, 0.52f, 2f, seed + 41);
    var crestField = TileableFractalNoise(x * (3.1f + waveScale * 2.6f) / (float)size * 6.2832f, y * (3.1f + waveScale * 2.6f) / (float)size * 6.2832f, Math.Max(2, (int)((float)size * (3.1f + waveScale * 2.6f) / 6.2832f)), 2, 0.56f, 2f, seed + 67);

    var directionalBands = DirBands(phaseX, phaseY, currentDirection, 3 + (int)MathF.Round(waveScale * 5f), (currentField - 0.5f) * (0.9f + currentStrength * 1.8f));
    var crossBands = DirBands(phaseX, phaseY, currentDirection + 0.25f, 1 + (int)MathF.Round(waveScale * 2f), crestField * 6.2832f);
    var checker = ((x + y) & 1) == 0 ? -0.012f : 0.012f;

    var depthVal = basin * 0.56f + pocket * 0.24f + currentField * 0.2f;
    depthVal = Lerp(depthVal, pocket, depthVariation * 0.26f);

    var waveLift = SmoothStep(0.34f - choppiness * 0.08f, 0.8f, directionalBands);
    var crestMask = SmoothStep(0.7f - choppiness * 0.12f, 0.98f, directionalBands) * (0.58f + crossBands * 0.42f);
    var tone = depthVal * 0.76f + waveLift * (0.15f + choppiness * 0.13f) + crossBands * 0.05f;
    tone = Math.Clamp(tone + checker * (0.45f + choppiness * 0.65f), 0f, 1f);

    // Base water color
    var r = SelW(tone, abyssR, deepR, midR, shallowR);
    var g = SelW(tone, abyssG, deepG, midG, shallowG);
    var b = SelW(tone, abyssB, deepB, midB, shallowB);

    // Crest brightening
    var cm = crestMask * (0.2f + waveScale * 0.14f);
    r = Lerp(r, crestR, cm);
    g = Lerp(g, crestG, cm);
    b = Lerp(b, crestB, cm);

    // Sparkles (small bright specular highlights on wave crests)
    if (foamDensity > 0.01f && crestMask > 0.05f)
    {
        var cellSz = Math.Max(4, (int)MathF.Round(size / (3.5f + foamDensity * 3f)));
        var prd = Math.Max(1, size / cellSz);
        var cx2 = x / cellSz;
        var cy2 = y / cellSz;
        var lx2 = x % cellSz;
        var ly2 = y % cellSz;
        var wx2 = Mod(cx2, prd);
        var wy2 = Mod(cy2, prd);

        var sparkleRoll = HashToUnit(wx2, wy2, seed + 101);
        var threshold = 0.9f - foamDensity * 0.26f - crestMask * 0.12f;
        if (sparkleRoll >= threshold)
        {
            var centX = Math.Min(cellSz - 2, 1 + (int)(HashToUnit(wx2, wy2, seed + 109) * Math.Max(1, cellSz - 2)));
            var centY = Math.Min(cellSz - 2, 1 + (int)(HashToUnit(wx2, wy2, seed + 113) * Math.Max(1, cellSz - 2)));
            var halfW = waveScale >= 0.72f ? 2 : waveScale >= 0.3f ? 1 : 0;
            var dY = Math.Abs(ly2 - centY);
            var dX = Math.Abs(lx2 - centX);

            if (dY == 0 && dX <= halfW)
            {
                var sparkBlend = 0.26f + crestMask * 0.34f;
                r = Lerp(r, sparkleR, sparkBlend);
                g = Lerp(g, sparkleG, sparkBlend);
                b = Lerp(b, sparkleB, sparkBlend);
            }

            if (dX == 0 && dY == 0)
            {
                var foamBlend = 0.38f + crestMask * 0.28f;
                r = Lerp(r, foamR, foamBlend);
                g = Lerp(g, foamG, foamBlend);
                b = Lerp(b, foamB, foamBlend);
            }
        }
    }

    // Foam patches on wave crests
    if (foamDensity > 0.01f && crestMask > 0.08f)
    {
        var foamNoise = TileableFractalNoise(x * (9f + waveScale * 10f) / (float)size * 6.2832f, y * (9f + waveScale * 10f) / (float)size * 6.2832f, Math.Max(2, (int)((float)size * (9f + waveScale * 10f) / 6.2832f)), 2, 0.5f, 2f, seed + 149);
        var foamThresh = 0.93f - foamDensity * 0.18f - crestMask * 0.1f;
        if (foamNoise > foamThresh)
        {
            var foamBlend = SmoothStep(foamThresh, 1f, foamNoise) * (0.2f + crestMask * 0.3f);
            r = Lerp(r, foamR, foamBlend);
            g = Lerp(g, foamG, foamBlend);
            b = Lerp(b, foamB, foamBlend);
        }
    }

    result.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return result;
